<?php require_once __DIR__.'/includes/auth.php'; require_once __DIR__.'/includes/helpers.php'; $u=require_login(); $msg=''; $err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $cur=$_POST['current_password']??''; $new=$_POST['new_password']??''; $new2=$_POST['new_password2']??''; $st=db()->prepare('SELECT password_hash FROM users WHERE id=?'); $st->execute([$u['id']]); $hash=$st->fetchColumn(); if(!password_verify($cur,$hash)){ $err='La contraseña actual no es correcta.'; } elseif(strlen($new)<(security_config()['min_password_length'] ?? 10)){ $err='La nueva contraseña debe tener al menos 10 caracteres.'; } elseif($new!==$new2){ $err='Las nuevas contraseñas no coinciden.'; } else { $st=db()->prepare('UPDATE users SET password_hash=?, updated_at=NOW() WHERE id=?'); $st->execute([password_hash($new,PASSWORD_DEFAULT),$u['id']]); $msg='Contraseña actualizada.'; } } ?>
<!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Mi Perfil</title><link rel="stylesheet" href="assets/css/app.css"><link rel="manifest" href="manifest.webmanifest"><link rel="icon" href="assets/icons/favicon.ico"></head><body class="dark-shell"><?php header_bar('Chess Coach'); ?><div class="app-area"><main class="wrap"><section class="card"><h2>Mi Perfil</h2><p class="muted">Usuario: <?=e($u['username'])?></p><?php if($msg): ?><p class="ok"><?=e($msg)?></p><?php endif; ?><?php if($err): ?><p class="error"><?=e($err)?></p><?php endif; ?><form method="post"><p><input type="password" name="current_password" placeholder="Contraseña actual" required></p><p><input type="password" name="new_password" placeholder="Nueva contraseña" required></p><p><input type="password" name="new_password2" placeholder="Repetir nueva contraseña" required></p><button>Cambiar contraseña</button> <a class="btn secondary" href="app.php">Volver</a></form></section></main></div><script src="assets/js/layout.js"></script></body></html>
